------------------------------------------------------------
----- TRIGGER FOR __mj_UpdatedAt field for the quotes table
------------------------------------------------------------
IF OBJECT_ID('[hubspot].[trgUpdatequotes]', 'TR') IS NOT NULL
    DROP TRIGGER [hubspot].[trgUpdatequotes];
GO
CREATE TRIGGER [hubspot].trgUpdatequotes
ON [hubspot].[quotes]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[quotes]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[quotes] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
GO
        